import React, { useState, useEffect } from 'react';

function App() {
  const roomOptions = ['Room A', 'Room B', 'Room C'];
  const [bookings, setBookings] = useState([]);
  const [roomId, setRoomId] = useState('');
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const response = await fetch('http://localhost:5000/bookings');
      if (!response.ok) {
        throw new Error('Failed to load bookings');
      }
      const data = await response.json();
      setBookings(data);
      setError(null);
    } catch (err) {
      console.error(err);
      setError(err.message);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccess(null);

    try {
      const response = await fetch('http://localhost:5000/bookings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          roomId,
          startTime: new Date(startTime),
          endTime: new Date(endTime),
        }),
      });

      const result = await response.json();
      if (!response.ok) {
        throw new Error(result.message || 'Booking failed');
      }

      setRoomId('');
      setStartTime('');
      setEndTime('');
      setSuccess('Booking added successfully');
      await fetchBookings();
    } catch (err) {
      console.error(err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <nav className="bg-blue-600 text-white p-4 shadow-md">
        <h1 className="text-xl font-bold">Meeting Room Booking</h1>
      </nav>
      <div className="container mx-auto p-4 max-w-5xl">
        <form onSubmit={handleSubmit} className="bg-white p-8 rounded-[32px] shadow-xl border border-gray-200 mb-8">
          <h2 className="text-lg font-semibold mb-4">Book a Room</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <select
              value={roomId}
              onChange={e => setRoomId(e.target.value)}
              required
              className="w-full border border-gray-300 p-3 rounded-xl bg-white text-sm focus:border-blue-400 focus:ring-2 focus:ring-blue-200 outline-none"
            >
              <option value="">Select Room</option>
              {roomOptions.map(room => (
                <option key={room} value={room}>{room}</option>
              ))}
            </select>
            <input
              type="datetime-local"
              value={startTime}
              onChange={e => setStartTime(e.target.value)}
              required
              className="w-full border border-gray-300 p-3 rounded-xl bg-white text-sm focus:border-blue-400 focus:ring-2 focus:ring-blue-200 outline-none"
            />
            <input
              type="datetime-local"
              value={endTime}
              onChange={e => setEndTime(e.target.value)}
              required
              className="w-full border border-gray-300 p-3 rounded-xl bg-white text-sm focus:border-blue-400 focus:ring-2 focus:ring-blue-200 outline-none"
            />
            <button
              type="submit"
              disabled={loading}
              className={`w-full md:w-auto px-6 py-3 rounded-xl text-white transition duration-200 ease-in-out ${loading ? 'bg-blue-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 shadow-sm hover:shadow-lg'}`}
            >
              {loading ? 'Booking...' : 'Book'}
            </button>
          </div>
          {error && (
            <div className="mt-4 rounded-md bg-red-50 p-4 text-red-800 border border-red-200">
              <p className="font-semibold">Error</p>
              <p>{error}</p>
            </div>
          )}
          {success && (
            <div className="mt-4 rounded-md bg-emerald-50 p-4 text-emerald-800 border border-emerald-200">
              <p className="font-semibold">Success</p>
              <p>{success}</p>
            </div>
          )}
        </form>
        <div className="bg-white p-8 rounded-[32px] shadow-xl border border-gray-200">
          <h2 className="text-lg font-semibold mb-4">All Bookings</h2>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200 border border-gray-200 shadow-sm">
              <thead className="bg-slate-50">
                <tr>
                  <th className="px-4 py-3 text-left text-sm font-semibold text-slate-700">Room ID</th>
                  <th className="px-4 py-3 text-left text-sm font-semibold text-slate-700">Start Time</th>
                  <th className="px-4 py-3 text-left text-sm font-semibold text-slate-700">End Time</th>
                  <th className="px-4 py-3 text-left text-sm font-semibold text-slate-700">Booked At</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-100">
                {bookings.map((booking, index) => (
                  <tr key={booking._id} className={`${index % 2 === 0 ? 'bg-white' : 'bg-slate-50'} hover:bg-blue-50 transition`}> 
                    <td className="px-4 py-3 text-sm text-slate-700">{booking.roomId}</td>
                    <td className="px-4 py-3 text-sm text-slate-700">{new Date(booking.startTime).toLocaleString()}</td>
                    <td className="px-4 py-3 text-sm text-slate-700">{new Date(booking.endTime).toLocaleString()}</td>
                    <td className="px-4 py-3 text-sm text-slate-700">{new Date(booking.bookedAt).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
